                // 如果有 prefab，用 prefab 的 Renderer
                _renderers = GetComponentsInChildren<Renderer>();
            }

            // 保存原始材质并替换为半透明
            _originalMaterials = new Material[_renderers.Length];
            for (int i = 0; i < _renderers.Length; i++)
            {
                _originalMaterials[i] = _renderers[i].sharedMaterial;
            }

            SetTransparency(0.6f);
            SetValid(true);
        }

        /// <summary>
        /// 更新幽灵位置和旋转。
        /// </summary>
        public void UpdatePosition(Vector3 worldPos, Vector2Int gridPos, int rotation)
        {
            transform.position = worldPos;
            GridPosition = gridPos;
            Rotation = rotation;
            transform.rotation = Quaternion.Euler(0f, rotation, 0f);
        }

        /// <summary>
        /// 设置预览状态：可放置（绿色）或不可放置（红色）。
        /// </summary>
        public void SetValid(bool isValid)
        {
            if (_isShowingValid == isValid) return;
            _isShowingValid = isValid;

            Material mat = isValid ? _validMaterial : _invalidMaterial;
            if (mat != null)
            {
                foreach (var r in _renderers)
                {
                    r.sharedMaterial = mat;
                }
            }
            else
            {
                // 没有自定义材质时，用颜色变化
                foreach (var r in _renderers)
                {
                    if (r.sharedMaterial != null)
                    {
                        var c = r.sharedMaterial.color;
                        r.sharedMaterial.color = isValid
                            ? new Color(0.5f, 1f, 0.5f, 0.6f)
                            : new Color(1f, 0.3f, 0.3f, 0.6f);
                    }
                }
            }
        }

        /// <summary>
        /// 清理幽灵，恢复原始材质。
        /// </summary>
        public void Cleanup()
        {
            for (int i = 0; i < _renderers.Length; i++)
            {
                if (_renderers[i] != null && _originalMaterials != null && i < _originalMaterials.Length)
                {
                    _renderers[i].sharedMaterial = _originalMaterials[i];
                }
            }
        }

        private void SetTransparency(float alpha)
        {
            foreach (var r in _renderers)
            {
                if (r.sharedMaterial != null)
                {
                    var c = r.sharedMaterial.color;
                    r.sharedMaterial.color = new Color(c.r, c.g, c.b, alpha);
                }
            }
        }
    }
}

