using UnityEngine;
using UnityEngine.UI;
using Sttop5.Modules.HomeBase;

// === 1. 设置 Ground 层到地面对象 ===
var terrain = UnityEngine.Object.FindObjectOfType<UnityEngine.Terrain>();
int groundLayerIndex = LayerMask.NameToLayer("Ground");
int setCount = 0;

if (terrain != null)
{
    terrain.gameObject.layer = groundLayerIndex;
    setCount++;
    Debug.Log($"[Setup] Terrain '{terrain.gameObject.name}' -> Ground layer");
}

// 也给所有 Free_Forest 根对象设置 Ground 层
foreach (var go in UnityEngine.Object.FindObjectsOfType<GameObject>())
{
    if (go.name.StartsWith("Free_Forest") && go.transform.parent == null)
    {
        go.layer = groundLayerIndex;
        setCount++;
        Debug.Log($"[Setup] '{go.name}' -> Ground layer");
    }
}

Debug.Log($"[Setup] 共 {setCount} 个对象设置 Ground 层");

// === 2. BuildingManager._availableBuildings 赋值 ===
var bm = UnityEngine.Object.FindObjectOfType<BuildingManager>();
if (bm != null)
{
    var guids = UnityEditor.AssetDatabase.FindAssets("t:BuildingData", new[] { "Assets/_Modules/HomeBase/Data" });
    var buildings = new System.Collections.Generic.List<BuildingData>();
    foreach (var guid in guids)
    {
        var path = UnityEditor.AssetDatabase.GUIDToAssetPath(guid);
        var data = UnityEditor.AssetDatabase.LoadAssetAtPath<BuildingData>(path);
        if (data != null)
        {
            buildings.Add(data);
            Debug.Log($"[Setup] 添加建筑: {data.buildingName} ({data.buildingType})");
        }
    }

    // 使用 SerializedObject 设置 _availableBuildings
    var so = new UnityEditor.SerializedObject(bm);
    var prop = so.FindProperty("_availableBuildings");
    prop.arraySize = buildings.Count;
    for (int i = 0; i < buildings.Count; i++)
    {
        prop.GetArrayElementAtIndex(i).objectReferenceValue = buildings[i];
    }
    so.ApplyModifiedProperties();
    Debug.Log($"[Setup] BuildingManager._availableBuildings 已设置 {buildings.Count} 个建筑");
}

// === 3. BuildModeController._groundLayer 设为 Ground ===
var bmc = UnityEngine.Object.FindObjectOfType<BuildModeController>();
if (bmc != null)
{
    var so = new UnityEditor.SerializedObject(bmc);
    var prop = so.FindProperty("_groundLayer");
    prop.intValue = 1 << groundLayerIndex;  // LayerMask value
    so.ApplyModifiedProperties();
    Debug.Log($"[Setup] BuildModeController._groundLayer = Ground (bit {groundLayerIndex})");
}

// === 4. BuildModeController._buildModeHintPanel 赋值 ===
if (bmc != null)
{
    // 查找"建造模式提示"面板
    var hintPanel = GameObject.Find("建造模式提示");
    if (hintPanel != null)
    {
        var so = new UnityEditor.SerializedObject(bmc);
        var prop = so.FindProperty("_buildModeHintPanel");
        prop.objectReferenceValue = hintPanel;
        so.ApplyModifiedProperties();
        Debug.Log("[Setup] BuildModeController._buildModeHintPanel -> 建造模式提示");
    }
    else
    {
        Debug.LogWarning("[Setup] 未找到 建造模式提示 对象");
    }
}

// === 5. BuildMenuUI 引用赋值 ===
var buildMenuUI = UnityEngine.Object.FindObjectOfType<BuildMenuUI>();
if (buildMenuUI != null)
{
    var so = new UnityEditor.SerializedObject(buildMenuUI);

    // _buttonContainer -> 建筑卡片容器
    var container = GameObject.Find("建筑卡片容器");
    if (container != null)
    {
        so.FindProperty("_buttonContainer").objectReferenceValue = container.transform;
        Debug.Log("[Setup] BuildMenuUI._buttonContainer -> 建筑卡片容器");
    }

    // _closeButton -> 关闭按钮
    var closeBtn = GameObject.Find("关闭按钮");
    if (closeBtn != null)
    {
        so.FindProperty("_closeButton").objectReferenceValue = closeBtn.GetComponent<Button>();
        Debug.Log("[Setup] BuildMenuUI._closeButton -> 关闭按钮");
    }

    // _buildingManager
    so.FindProperty("_buildingManager").objectReferenceValue = bm;

    // _buildModeController
    so.FindProperty("_buildModeController").objectReferenceValue = bmc;

    // 分类标签按钮
    var tabNames = new[] { "资源类", "传送类", "仓库类", "装饰类", "特殊类" };
    var tabFields = new[] { "_tabResource", "_tabPortal", "_tabStorage", "_tabDecoration", "_tabSpecial" };
    for (int i = 0; i < tabNames.Length; i++)
    {
        var tabGo = GameObject.Find(tabNames[i]);
        if (tabGo != null)
        {
            var btn = tabGo.GetComponentInChildren<Button>();
            if (btn == null) btn = tabGo.AddComponent<Button>();
            so.FindProperty(tabFields[i]).objectReferenceValue = btn;
            Debug.Log($"[Setup] BuildMenuUI.{tabFields[i]} -> {tabNames[i]}");
        }
    }

    so.ApplyModifiedProperties();
    Debug.Log("[Setup] BuildMenuUI 所有引用已赋值");
}

// === 6. 建造按钮绑定 BuildMenuUI.Open() ===
var buildBtn = GameObject.Find("建造按钮");
if (buildBtn != null && buildMenuUI != null)
{
    var btn = buildBtn.GetComponent<Button>();
    if (btn == null)
    {
        btn = buildBtn.AddComponent<Button>();
        Debug.Log("[Setup] 为 建造按钮 添加了 Button 组件");
    }
    btn.onClick.RemoveAllListeners();
    btn.onClick.AddListener(buildMenuUI.Open);
    Debug.Log("[Setup] 建造按钮 -> BuildMenuUI.Open()");
}

// === 7. 创建建筑信息弹窗 UI ===
var canvas = GameObject.Find("界面画布");
if (canvas != null)
{
    // 检查是否已存在
    var existingPanel = GameObject.Find("建筑信息面板");
    if (existingPanel == null)
    {
        var panel = new GameObject("建筑信息面板");
        panel.transform.SetParent(canvas.transform, false);
        var rect = panel.AddComponent<RectTransform>();
        rect.anchorMin = new Vector2(0.5f, 0.5f);
        rect.anchorMax = new Vector2(0.5f, 0.5f);
        rect.sizeDelta = new Vector2(300f, 280f);
        panel.AddComponent<CanvasGroup>();

        var img = panel.AddComponent<Image>();
        img.color = new Color(0.15f, 0.15f, 0.2f, 0.95f);

        var infoPanel = panel.AddComponent<BuildingInfoPanel>();

        // 标题文字
        var nameGo = CreateTextElement(panel.transform, "建筑名称", 24, new Vector2(-30f, 100f), new Vector2(200f, 30f));
        var levelGo = CreateTextElement(panel.transform, "Lv.1", 18, new Vector2(100f, 100f), new Vector2(60f, 30f));

        // 描述
        var descGo = CreateTextElement(panel.transform, "描述", 14, new Vector2(0f, 40f), new Vector2(260f, 60f));
        var descText = descGo.GetComponent<UnityEngine.UI.Text>();
        descText.alignment = TextAnchor.UpperLeft;
        descText.fontSize = 13;

        // 升级费用
        var costGo = CreateTextElement(panel.transform, "0G", 16, new Vector2(0f, -10f), new Vector2(100f, 25f));

        // 升级按钮
        var upgradeBtn = CreateButtonElement(panel.transform, "升级", new Vector2(-60f, -60f), new Vector2(100f, 35f));

        // 拆除按钮
        var demolishBtn = CreateButtonElement(panel.transform, "拆除", new Vector2(60f, -60f), new Vector2(100f, 35f));
        var demolishImg = demolishBtn.GetComponent<Image>();
        demolishImg.color = new Color(0.8f, 0.2f, 0.2f, 1f);

        // 关闭按钮
        var closeInfoBtn = CreateButtonElement(panel.transform, "✕", new Vector2(130f, 120f), new Vector2(30f, 30f));

        // 绑定 BuildingInfoPanel 引用
        var so = new UnityEditor.SerializedObject(infoPanel);
        so.FindProperty("_nameText").objectReferenceValue = nameGo.GetComponent<UnityEngine.UI.Text>();
        so.FindProperty("_levelText").objectReferenceValue = levelGo.GetComponent<UnityEngine.UI.Text>();
        so.FindProperty("_descText").objectReferenceValue = descGo.GetComponent<UnityEngine.UI.Text>();
        so.FindProperty("_upgradeCostText").objectReferenceValue = costGo.GetComponent<UnityEngine.UI.Text>();
        so.FindProperty("_upgradeButton").objectReferenceValue = upgradeBtn.GetComponent<Button>();
        so.FindProperty("_demolishButton").objectReferenceValue = demolishBtn.GetComponent<Button>();
        so.FindProperty("_closeButton").objectReferenceValue = closeInfoBtn.GetComponent<Button>();
        so.FindProperty("_buildingManager").objectReferenceValue = bm;
        so.ApplyModifiedProperties();

        panel.SetActive(false);
        Debug.Log("[Setup] 建筑信息面板已创建并绑定");
    }
    else
    {
        Debug.Log("[Setup] 建筑信息面板已存在，跳过创建");
    }
}

Debug.Log("[Setup] === 全部场景接线完成 ===");

