        so2.FindProperty("_levelText").objectReferenceValue = levelGo.GetComponent<UnityEngine.UI.Text>();
        so2.FindProperty("_descText").objectReferenceValue = descGo.GetComponent<UnityEngine.UI.Text>();
        so2.FindProperty("_upgradeCostText").objectReferenceValue = costGo.GetComponent<UnityEngine.UI.Text>();
        so2.FindProperty("_upgradeButton").objectReferenceValue = upgradeGo.GetComponent<UnityEngine.UI.Button>();
        so2.FindProperty("_demolishButton").objectReferenceValue = demolishGo.GetComponent<UnityEngine.UI.Button>();
        so2.FindProperty("_closeButton").objectReferenceValue = closeInfoGo.GetComponent<UnityEngine.UI.Button>();
