var infoPanel = infoTf.GetComponent<BuildingInfoPanel>();
if (infoPanel == null) { Debug.LogError("BuildingInfoPanel component not found"); return; }

var so = new UnityEditor.SerializedObject(hm);
so.FindProperty("_buildingInfoPanel").objectReferenceValue = infoPanel;
so.ApplyModifiedProperties();
