    /// <summary>
    /// 建筑管理器，负责建筑的放置、升级和拆除。
    /// </summary>
    public class BuildingManager : MonoBehaviour
    {
        [Header("建筑配置列表")]
        [SerializeField] private BuildingData[] _availableBuildings;
        [SerializeField] private GridManager _gridManager;

        private List<BuildingBase> _buildings = new List<BuildingBase>();

        /// <summary>建筑被放置时触发，可用于注册点击事件等。</summary>
        public event System.Action<BuildingBase> OnBuildingPlaced;

        public BuildingData[] AvailableBuildings => _availableBuildings;
        public IReadOnlyList<BuildingBase> Buildings => _buildings;
        public GridManager Grid => _gridManager;

        #region 放置与检测

        /// <summary>
        /// 在指定世界坐标放置建筑（2.5D：XZ 平面）。
        /// </summary>
        public BuildingBase PlaceBuilding(BuildingData data, Vector3 worldPos)
        {
            // 扣除建造费用
            var levelData = data.GetLevelData(1);
            var profile = PlayerProfile.Instance;
            if (profile != null && levelData.buildCost > 0 && !profile.HasEnoughGold(levelData.buildCost))
            {
                Debug.LogWarning("[BuildingManager] 金币不足");
                return null;
            }
            profile?.SpendGold(levelData.buildCost, "building_place");

            // 实例化建筑
            GameObject go = data.prefab != null
                ? Instantiate(data.prefab, worldPos, Quaternion.identity, transform)
                : CreatePlaceholderBuilding(data, worldPos);

            BuildingBase building = go.GetComponent<BuildingBase>();
            if (building == null)
                building = go.AddComponent<BuildingBase>();

            building.Initialize(data);
            _buildings.Add(building);

            // 占用网格
            if (_gridManager != null)
            {
                Vector2Int gridPos = _gridManager.WorldToGrid(worldPos);
                _gridManager.OccupyArea(gridPos, data.gridSize, building);
                building.SetGridInfo(gridPos, 0);
            }

            OnBuildingPlaced?.Invoke(building);

            Debug.Log($"[BuildingManager] 建筑已放置: {data.buildingName} at {worldPos}");
            return building;
        }

        /// <summary>
        /// 拆除指定建筑，释放网格占用。
        /// </summary>
        public bool RemoveBuilding(BuildingBase building)
        {
            if (building == null || !_buildings.Contains(building))
                return false;

            // 释放网格占用
            if (_gridManager != null)
                _gridManager.ReleaseBuilding(building);

            _buildings.Remove(building);
            building.Demolish();
            return true;
        }

        /// <summary>
        /// 获取指定位置附近的建筑。
        /// </summary>
        public BuildingBase GetBuildingNear(Vector3 worldPos, float radius = 1f)
        {
            float minDist = float.MaxValue;
            BuildingBase nearest = null;
            foreach (var b in _buildings)
            {
                if (b == null) continue;
                float dist = Vector3.Distance(b.transform.position, worldPos);
                if (dist < radius && dist < minDist)
                {
                    minDist = dist;
                    nearest = b;
                }
            }
            return nearest;
        }

        #endregion

        #region 存档

        /// <summary>
        /// 导出所有建筑的存档数据。
        /// </summary>
        public List<BuildingSaveEntry> ExportSaveData()
        {
            var result = new List<BuildingSaveEntry>();
            foreach (var building in _buildings)
            {
                if (building == null) continue;
                result.Add(new BuildingSaveEntry
                {
                    buildingId = building.Data.buildingId,
                    posX = building.transform.position.x,
                    posY = 0f,
                    posZ = building.transform.position.z,
                    rotation = building.Rotation,
                    level = building.CurrentLevel
                });
            }
            return result;
        }

        /// <summary>
        /// 从存档数据恢复所有建筑。
        /// </summary>
        public void RestoreFromSaveData(List<BuildingSaveEntry> entries)
        {
            if (entries == null) return;

            foreach (var entry in entries)
            {
                BuildingData data = FindBuildingData(entry.buildingId);
                if (data == null)
                {
                    Debug.LogWarning($"[BuildingManager] 未找到建筑配置: {entry.buildingId}");
                    continue;
                }

                // 兼容旧 2D 存档：如果 posZ 为 0 且 posY 不为 0，用 posY 作为 Z
                float z = entry.posZ;
                if (z == 0f && entry.posY != 0f)
                    z = entry.posY;

                Vector3 worldPos = new Vector3(entry.posX, 0f, z);
                GameObject go = data.prefab != null
                    ? Instantiate(data.prefab, worldPos, Quaternion.Euler(0f, entry.rotation, 0f), transform)
                    : CreatePlaceholderBuilding(data, worldPos);

                BuildingBase building = go.GetComponent<BuildingBase>();
                if (building == null)
                    building = go.AddComponent<BuildingBase>();

                building.RestoreFromSave(data, entry.level);
                building.SetGridInfo(
                    _gridManager != null ? _gridManager.WorldToGrid(worldPos) : Vector2Int.zero,
                    entry.rotation
                );

                // 恢复旋转
                building.transform.rotation = Quaternion.Euler(0f, entry.rotation, 0f);

                // 占用网格
                if (_gridManager != null)
                {
                    Vector2Int gridPos = _gridManager.WorldToGrid(worldPos);
                    _gridManager.OccupyArea(gridPos, data.gridSize, building);
                }

                _buildings.Add(building);
            }

            Debug.Log($"[BuildingManager] 从存档恢复 {entries.Count} 个建筑");
        }

        #endregion

        #region 辅助

        private BuildingData FindBuildingData(string buildingId)
        {
            if (_availableBuildings == null) return null;
            foreach (var data in _availableBuildings)
            {
                if (data.buildingId == buildingId)
                    return data;
            }
            return null;
        }

        private GameObject CreatePlaceholderBuilding(BuildingData data, Vector3 worldPos)
        {
            GameObject go = GameObject.CreatePrimitive(PrimitiveType.Cube);
            go.name = $"Building_{data.buildingName}";
            go.transform.position = worldPos + new Vector3(0f, 0.25f, 0f);
            go.transform.SetParent(transform);
            go.transform.localScale = new Vector3(data.gridSize.x, 0.5f, data.gridSize.y);

            var renderer = go.GetComponent<Renderer>();
            var mat = new Material(Shader.Find("Universal Render Pipeline/Lit"));
            mat.color = GetBuildingColor(data.buildingType);
            renderer.sharedMaterial = mat;

            // 移除碰撞器（建筑不需要物理）
            var collider = go.GetComponent<Collider>();
            if (collider != null) DestroyImmediate(collider);

            return go;
        }

        private Color GetBuildingColor(BuildingType type)
        {
            switch (type)
            {
                case BuildingType.ResourceGen: return new Color(0.2f, 0.8f, 0.3f);
                case BuildingType.Portal: return new Color(0.3f, 0.5f, 1f);
                case BuildingType.Storage: return new Color(0.9f, 0.7f, 0.2f);
                case BuildingType.Decoration: return new Color(0.9f, 0.4f, 0.7f);
                case BuildingType.Special: return new Color(1f, 0.5f, 0.1f);
                default: return Color.white;
            }
        }

        #endregion
    }
}

using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑基类，所有建筑类型继承此类。
    /// 管理建筑的等级、升级和拆除。
    /// </summary>
    public class BuildingBase : MonoBehaviour
    {
        [Header("建筑配置")]
        [SerializeField] protected BuildingData _data;

        protected int _currentLevel = 1;
        protected bool _isPlaced = false;
        protected float _productionTimer;
        protected Vector2Int _gridPos;
        protected int _rotation;

        /// <summary>建筑被点击时触发，参数为被点击的建筑实例。</summary>
        public event System.Action<BuildingBase> OnBuildingClicked;

        #region 属性

        public BuildingData Data => _data;
        public int CurrentLevel => _currentLevel;
        public bool IsPlaced => _isPlaced;
        public bool IsMaxLevel => _currentLevel >= _data.MaxLevel;
        public BuildingLevel CurrentLevelData => _data.GetLevelData(_currentLevel);
        public Vector2Int GridPos => _gridPos;
        public int Rotation => _rotation;

        #endregion

        #region 初始化

        /// <summary>
        /// 初始化建筑。
        /// </summary>
        public virtual void Initialize(BuildingData data)
        {
            _data = data;
            _currentLevel = 1;
            _isPlaced = true;
            _productionTimer = 0f;
        }

        /// <summary>
        /// 从存档恢复建筑状态。
        /// </summary>
        public virtual void RestoreFromSave(BuildingData data, int level)
        {
            _data = data;
            _currentLevel = Mathf.Clamp(level, 1, data.MaxLevel);
            _isPlaced = true;
            _productionTimer = 0f;
        }

        /// <summary>
        /// 设置建筑的网格位置和旋转。
        /// </summary>
        public void SetGridInfo(Vector2Int gridPos, int rotation)
        {
            _gridPos = gridPos;
            _rotation = rotation;
        }

        #endregion

        #region 升级与拆除

        /// <summary>
        /// 升级建筑。
        /// </summary>
        public virtual bool Upgrade()
        {
            if (IsMaxLevel)
            {
                Debug.LogWarning($"[BuildingBase] 建筑已满级: {_data.buildingName}");
                return false;
            }

            var levelData = _data.GetLevelData(_currentLevel + 1);
            var profile = PlayerProfile.Instance;
            if (profile == null || !profile.HasEnoughGold(levelData.upgradeCost))
            {
                Debug.LogWarning($"[BuildingBase] 金币不足，无法升级: {_data.buildingName}");
                return false;
            }

            profile.SpendGold(levelData.upgradeCost, "building_upgrade");
            _currentLevel++;
            OnUpgraded();
            Debug.Log($"[BuildingBase] 建筑升级: {_data.buildingName} Lv.{_currentLevel}");
            return true;
        }

        /// <summary>
        /// 拆除建筑，返还部分资源。
        /// </summary>
        public virtual int Demolish()
        {
            int refund = GetSellValue();
            var profile = PlayerProfile.Instance;
            profile?.AddGold(refund, "building_demolish");
            _isPlaced = false;
            Debug.Log($"[BuildingBase] 建筑拆除: {_data.buildingName}, 返还 {refund} 金币");
            Destroy(gameObject);
            return refund;
        }

        /// <summary>
        /// 获取出售价值（建造费用的 60%）。
        /// </summary>
        public int GetSellValue()
        {
            int totalCost = 0;
            for (int i = 1; i <= _currentLevel; i++)
            {
                var ld = _data.GetLevelData(i);
                totalCost += i == 1 ? ld.buildCost : ld.upgradeCost;
            }
            return Mathf.RoundToInt(totalCost * 0.6f);
        }

        #endregion

        #region 子类重写

        /// <summary>升级后的回调。</summary>
        protected virtual void OnUpgraded() { }

        /// <summary>每帧更新（用于资源产出等）。</summary>
        protected virtual void BuildingUpdate() { }

        #endregion

        private void OnMouseDown()
        {
            if (!_isPlaced) return;
            OnBuildingClicked?.Invoke(this);
        }

        private void Update()
        {
            // 场景中预放置的建筑：如果已有 _data 但 _isPlaced 为 false，自动标记
            if (!_isPlaced && _data != null)
            {
                _isPlaced = true;
            }

            if (!_isPlaced) return;
            BuildingUpdate();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑类型枚举。
    /// </summary>
    public enum BuildingType
    {
        ResourceGen,    // 资源产出建筑
        Portal,         // 传送门（进入小游戏）
        Storage,        // 仓库（提升资源上限）
        Decoration,     // 装饰建筑
        Special         // 特殊建筑
    }

    /// <summary>
    /// 建筑等级配置。
    /// </summary>
    [Serializable]
    public class BuildingLevel
    {
        public int level;
        public int upgradeCost;
        public int buildCost;
        public float productionRate;    // 每秒产出量
        public int productionCapacity;  // 产出上限
        public int storageCapacity;     // 仓库容量（仅 Storage 类型）
    }

    /// <summary>
    /// 建筑配置数据（ScriptableObject）。
    /// 在 Inspector 中编辑，定义建筑的所有属性。
    /// </summary>
    [CreateAssetMenu(fileName = "NewBuilding", menuName = "HomeBase/Building Data")]
    public class BuildingData : ScriptableObject
    {
        [Header("基础信息")]
        public string buildingId;
        public string buildingName;
        [TextArea(2, 4)]
        public string description;
        public BuildingType buildingType;
        public Sprite icon;
        public GameObject prefab;

        [Header("网格配置")]
        public Vector2Int gridSize = Vector2Int.one;  // 占据的网格大小

        [Header("等级配置")]
        public BuildingLevel[] levels;

        [Header("传送门配置（仅 Portal 类型）")]
        public string targetModuleId;    // 目标模块 ID（如 "towerdefense"）
        public string targetSceneName;   // 目标场景名

        [Header("产出资源类型（仅 ResourceGen 类型）")]
        public ResourceType producedResource = ResourceType.Gold;

        /// <summary>获取指定等级的配置，超出范围返回最高等级。</summary>
        public BuildingLevel GetLevelData(int level)
        {
            if (levels == null || levels.Length == 0)
                return new BuildingLevel { level = 1, buildCost = 100 };
            int index = Mathf.Clamp(level - 1, 0, levels.Length - 1);
            return levels[index];
        }

        /// <summary>最大等级。</summary>
        public int MaxLevel => levels != null ? levels.Length : 1;
    }
}

using UnityEngine;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑预览幽灵，跟随鼠标在网格上移动，显示可放置状态（绿/红）。
    /// 使用材质实例（而非直接改 sharedMaterial）避免污染项目材质文件。
    /// </summary>
    public class GhostPreview : MonoBehaviour
    {
        [Header("材质")]
        [SerializeField] private Material _validMaterial;
        [SerializeField] private Material _invalidMaterial;

        private Renderer[] _renderers;
        /// <summary>每个 renderer 对应的运行时材质实例，不会污染项目文件。</summary>
        private Material[] _ghostMaterials;
        private bool _isShowingValid = true;

        public BuildingData Data { get; private set; }
        public Vector2Int GridPosition { get; private set; }
        public int Rotation { get; private set; }

        private void Awake()
        {
            _renderers = GetComponentsInChildren<Renderer>();
        }

        /// <summary>
        /// 用建筑数据初始化幽灵。
        /// </summary>
        public void Initialize(BuildingData data)
        {
            Data = data;

            if (data.prefab != null)
            {
                _renderers = GetComponentsInChildren<Renderer>();
            }

            // 为每个 Renderer 创建独立的材质实例，避免污染原始材质
            _ghostMaterials = new Material[_renderers.Length];
            for (int i = 0; i < _renderers.Length; i++)
            {
                _ghostMaterials[i] = new Material(_renderers[i].sharedMaterial);
                _renderers[i].sharedMaterial = _ghostMaterials[i];
            }

            SetTransparency(0.6f);
            SetValid(true);
        }

        /// <summary>
        /// 更新幽灵位置和旋转。
        /// </summary>
        public void UpdatePosition(Vector3 worldPos, Vector2Int gridPos, int rotation)
        {
            transform.position = worldPos;
            GridPosition = gridPos;
            Rotation = rotation;
            transform.rotation = Quaternion.Euler(0f, rotation, 0f);
        }

        /// <summary>
        /// 设置预览状态：可放置（绿色）或不可放置（红色）。
        /// </summary>
        public void SetValid(bool isValid)
        {
            if (_isShowingValid == isValid) return;
            _isShowingValid = isValid;

            Material template = isValid ? _validMaterial : _invalidMaterial;
            if (template != null)
            {
                foreach (var r in _renderers)
                {
                    var inst = new Material(template);
                    r.sharedMaterial = inst;
                }
            }
            else
            {
                foreach (var r in _renderers)
                {
                    if (r.sharedMaterial != null)
                    {
                        var c = r.sharedMaterial.color;
                        r.sharedMaterial.color = isValid
                            ? new Color(0.5f, 1f, 0.5f, 0.6f)
                            : new Color(1f, 0.3f, 0.3f, 0.6f);
                    }
                }
            }
        }

        /// <summary>
        /// 清理幽灵，销毁运行时创建的材质实例。
        /// </summary>
        public void Cleanup()
        {
            if (_ghostMaterials != null)
            {
                foreach (var mat in _ghostMaterials)
                {
                    if (mat != null) Destroy(mat);
                }
            }
        }

        private void SetTransparency(float alpha)
        {
            foreach (var r in _renderers)
            {
                if (r.sharedMaterial != null)
                {
                    var c = r.sharedMaterial.color;
                    r.sharedMaterial.color = new Color(c.r, c.g, c.b, alpha);
                }
            }
        }

        private void OnDestroy()
        {
            Cleanup();
        }
    }
}

using UnityEngine;
using UnityEngine.SceneManagement;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 传送门建筑，点击后切换到目标场景。
    /// </summary>
    public class PortalBuilding : BuildingBase
    {
        [Header("传送门特效")]
        [SerializeField] private Color _portalColor = new Color(0.3f, 0.5f, 1f, 0.8f);
        [SerializeField] private float _pulseSpeed = 2f;
        [SerializeField] private float _pulseAmount = 0.1f;

        private SpriteRenderer _renderer;
        private float _timer;
        private bool _isHovered = false;
        private Vector3 _baseScale;

        public string TargetModuleId => _data != null ? _data.targetModuleId : "";
        public string TargetSceneName => _data != null ? _data.targetSceneName : "";

        protected override void OnUpgraded()
        {
        }

        private void Start()
        {
            if (_data != null && !_isPlaced)
            {
                _isPlaced = true;
            }

            _renderer = GetComponent<SpriteRenderer>();
            _baseScale = transform.localScale;
            if (_renderer != null)
            {
                _renderer.color = _portalColor;
            }
        }

        private new void Update()
        {
            if (!_isPlaced && _data != null)
            {
                _isPlaced = true;
            }

            _timer += Time.deltaTime;

            if (_renderer != null)
            {
                float pulse = 1f + Mathf.Sin(_timer * _pulseSpeed) * _pulseAmount;
                transform.localScale = _baseScale * pulse;
            }
        }

        /// <summary>
        /// 点击传送门，切换到目标场景。
        /// </summary>
        public void OnPortalClicked()
        {
            string sceneName = TargetSceneName;
            if (string.IsNullOrEmpty(sceneName))
            {
                Debug.LogWarning("[PortalBuilding] 未配置目标场景");
                return;
            }

            Debug.Log($"[PortalBuilding] 进入传送门: {_data.buildingName} → 场景 {sceneName}");
            SceneManager.LoadScene(sceneName);
        }

        private void OnMouseDown()
        {
            if (!_isPlaced) return;
            OnPortalClicked();
        }

        private void OnMouseEnter()
        {
            _isHovered = true;
            if (_renderer != null)
                _renderer.color = new Color(_portalColor.r, _portalColor.g, _portalColor.b, 1f);
        }

        private void OnMouseExit()
        {
            _isHovered = false;
            if (_renderer != null)
                _renderer.color = _portalColor;
        }
    }
}

using UnityEngine;
using TowerDefense.Core;
using TowerDefense.Data;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 挂在 Knight 上，处理点击树木→走过去→自动砍树的完整交互流程。
    /// 与 ClickToMoveController 协同工作：砍树时暂停普通点击移动。
    /// </summary>
    public class PlayerInteractor : MonoBehaviour
    {
        [Header("砍树参数")]
        [SerializeField] private float _chopRange = 2f;
        [SerializeField] private float _chopDamage = 10f;
        [SerializeField] private float _chopInterval = 0.8f;

        private ClickToMoveController _moveController;
        private CharacterController _cc;
        private Animator _anim;
        private Camera _cam;

        private TreeResource _targetTree;
        private bool _isChopping;
        private float _chopTimer;

        // Animator parameter IDs
        private static readonly int AnimInteract = Animator.StringToHash("Interact");
        private static readonly int AnimSpeed = Animator.StringToHash("Speed");

        public bool IsChopping => _isChopping;

        private void Awake()
        {
            _moveController = GetComponent<ClickToMoveController>();
            _cc = GetComponent<CharacterController>();
            _anim = GetComponent<Animator>();
            // Camera 被 ClickToMoveController 解除了父子关系，用 Camera.main 查找
            _cam = Camera.main;
        }

        private void Update()
        {
            HandleTreeClick();

            if (_isChopping && _targetTree != null)
            {
                UpdateChopping();
            }
        }

        private void HandleTreeClick()
        {
            if (!Input.GetMouseButtonDown(0)) return;
            if (_cam == null) return;

            // 点在 UI 上时不处理
            if (UnityEngine.EventSystems.EventSystem.current != null &&
                UnityEngine.EventSystems.EventSystem.current.IsPointerOverGameObject())
                return;

            Ray ray = _cam.ScreenPointToRay(Input.mousePosition);
            if (!Physics.Raycast(ray, out RaycastHit hit, 200f)) return;

            // 通过 Tag 查找可砍伐的树
            if (!hit.collider.CompareTag("Tree")) return;
            TreeResource tree = hit.collider.GetComponentInParent<TreeResource>();
            if (tree == null || tree.IsDead) return;

            // 设置目标树，开始走向它
            _targetTree = tree;
            _isChopping = false;
            _chopTimer = 0f;

            // 让移动控制器走向树
            _moveController.SetInteractionTarget(tree.ChopPosition, _chopRange);
        }

        private void UpdateChopping()
        {
            // 目标树已被砍倒
            if (_targetTree == null || _targetTree.IsDead)
            {
                StopChopping();
                return;
            }

            // 检查距离，太远则走过去
            float dist = Vector3.Distance(transform.position, _targetTree.ChopPosition);
            if (dist > _chopRange + 0.3f)
            {
                // 还在走向树
                _moveController.SetInteractionTarget(_targetTree.ChopPosition, _chopRange);
                return;
            }

            // 面向树
            Vector3 dir = (_targetTree.ChopPosition - transform.position);
            dir.y = 0f;
            if (dir.sqrMagnitude > 0.01f)
            {
                transform.rotation = Quaternion.Slerp(
                    transform.rotation,
                    Quaternion.LookRotation(dir),
                    8f * Time.deltaTime);
            }

            // 开始/继续砍树
            if (!_isChopping)
            {
                _isChopping = true;
                _moveController.PauseMovement();
            }

            _chopTimer += Time.deltaTime;
            if (_chopTimer >= _chopInterval)
            {
                _chopTimer = 0f;
                ChopOnce();
            }
        }

        private void ChopOnce()
        {
            if (_anim != null)
                _anim.SetTrigger(AnimInteract);

            if (_targetTree != null && !_targetTree.IsDead)
            {
                bool stillAlive = _targetTree.TakeChopDamage(_chopDamage);
                if (!stillAlive)
                {
                    // 树倒了，发奖励
                    GiveReward();
                    StopChopping();
                }
            }
        }

        private void GiveReward()
        {
            // 通过 EventBus 发放金币
            var wallet = PlayerWallet.Instance;
            if (wallet != null)
            {
                wallet.AddGold(5);
            }
        }

        private void StopChopping()
        {
            _isChopping = false;
            _targetTree = null;
            _chopTimer = 0f;
            _moveController.ResumeMovement();
        }

        /// <summary>外部取消交互（如点击地面移动时）</summary>
        public void CancelInteraction()
        {
            StopChopping();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 资源建筑，自动产出资源。
    /// </summary>
    public class ResourceBuilding : BuildingBase
    {
        private float _accumulated;

        protected override void BuildingUpdate()
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen)
                return;

            var levelData = CurrentLevelData;
            if (levelData.productionRate <= 0) return;

            _productionTimer += Time.deltaTime;
            float interval = 1f / levelData.productionRate;

            if (_productionTimer >= interval)
            {
                _productionTimer -= interval;
                _accumulated++;

                if (_accumulated >= levelData.productionCapacity)
                {
                    CollectResources();
                }
            }
        }

        /// <summary>
        /// 收集已产出的资源。
        /// </summary>
        public int CollectResources()
        {
            int collected = (int)_accumulated;
            if (collected <= 0) return 0;

            _accumulated = 0;

            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                switch (_data.producedResource)
                {
                    case ResourceType.Gold:
                        profile.AddGold(collected, "home_resource");
                        break;
                    case ResourceType.Diamond:
                        profile.AddDiamond(collected, "home_resource");
                        break;
                }
            }

            Debug.Log($"[ResourceBuilding] 收集 {collected} {_data.producedResource} from {_data.buildingName}");
            return collected;
        }

        /// <summary>
        /// 计算离线收益。
        /// </summary>
        public int CalculateOfflineEarnings(float offlineSeconds)
        {
            if (_data == null || _data.buildingType != BuildingType.ResourceGen) return 0;
            var levelData = CurrentLevelData;
            return Mathf.FloorToInt(levelData.productionRate * offlineSeconds);
        }

        protected override void OnUpgraded()
        {
            // 升级后立即收集一次
            CollectResources();
        }
    }
}

using System;
using System.Collections.Generic;
using UnityEngine;
using Sttop5.Shared.Core;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 资源管理器，管理家园中的资源产出和收集。
    /// </summary>
    public class ResourceManager : MonoBehaviour
    {
        [Header("本地资源")]
        [SerializeField] private int _wood = 0;
        [SerializeField] private int _stone = 0;
        [SerializeField] private int _food = 0;

        public int Wood => _wood;
        public int Stone => _stone;
        public int Food => _food;

        public event Action<int, int, int> OnLocalResourcesChanged;

        #region 本地资源操作

        public void AddWood(int amount)
        {
            if (amount <= 0) return;
            _wood += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void AddStone(int amount)
        {
            if (amount <= 0) return;
            _stone += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void AddFood(int amount)
        {
            if (amount <= 0) return;
            _food += amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public bool SpendWood(int amount)
        {
            if (_wood < amount) return false;
            _wood -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        public bool SpendStone(int amount)
        {
            if (_stone < amount) return false;
            _stone -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        public bool SpendFood(int amount)
        {
            if (_food < amount) return false;
            _food -= amount;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
            return true;
        }

        #endregion

        #region 收集所有建筑产出

        /// <summary>
        /// 收集所有资源建筑的产出。
        /// </summary>
        public void CollectAllResources()
        {
            var buildingManager = FindObjectOfType<BuildingManager>();
            if (buildingManager == null) return;

            int totalCollected = 0;
            foreach (var building in buildingManager.Buildings)
            {
                var resourceBuilding = building as ResourceBuilding;
                if (resourceBuilding != null)
                {
                    totalCollected += resourceBuilding.CollectResources();
                }
            }

            if (totalCollected > 0)
            {
                Debug.Log($"[ResourceManager] 收集所有建筑产出: {totalCollected}");
            }
        }

        #endregion

        #region 存档

        public void LoadFromSave(HomeSaveData data)
        {
            if (data == null) return;
            _wood = data.wood;
            _stone = data.stone;
            _food = data.food;
            OnLocalResourcesChanged?.Invoke(_wood, _stone, _food);
        }

        public void SaveToSave(HomeSaveData data)
        {
            data.wood = _wood;
            data.stone = _stone;
            data.food = _food;
        }

        #endregion
    }
}

using System.Collections.Generic;
using UnityEngine;
using UnityEngine.UI;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建造菜单 UI，显示可建造的建筑列表，支持分类筛选。
    /// 点击建筑按钮后进入建造模式（由 BuildModeController 管理）。
    /// </summary>
    public class BuildMenuUI : MonoBehaviour
    {
        [Header("UI 引用")]
        [SerializeField] private Transform _buttonContainer;
        [SerializeField] private GameObject _buildButtonPrefab;
        [SerializeField] private Button _closeButton;

        [Header("分类标签")]
        [SerializeField] private Button _tabResource;
        [SerializeField] private Button _tabPortal;
        [SerializeField] private Button _tabStorage;
        [SerializeField] private Button _tabDecoration;
        [SerializeField] private Button _tabSpecial;
        [SerializeField] private Color _tabActiveColor = new Color(0.3f, 0.7f, 1f, 1f);
        [SerializeField] private Color _tabInactiveColor = new Color(0.5f, 0.5f, 0.5f, 1f);

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private BuildModeController _buildModeController;

        private BuildingType _currentTab = BuildingType.ResourceGen;
        private readonly Dictionary<BuildingType, Button> _tabButtons = new Dictionary<BuildingType, Button>();

        private void Awake()
        {
            if (_closeButton != null)
                _closeButton.onClick.AddListener(Close);

            // 注册分类标签点击事件
            _tabButtons[BuildingType.ResourceGen] = _tabResource;
            _tabButtons[BuildingType.Portal] = _tabPortal;
            _tabButtons[BuildingType.Storage] = _tabStorage;
            _tabButtons[BuildingType.Decoration] = _tabDecoration;
            _tabButtons[BuildingType.Special] = _tabSpecial;

            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value != null)
                {
                    var type = kvp.Key;
                    kvp.Value.onClick.AddListener(() => SwitchTab(type));
                }
            }
        }

        private void OnDestroy()
        {
            if (_closeButton != null)
                _closeButton.onClick.RemoveListener(Close);
        }

        private void OnEnable()
        {
            RefreshButtons();
            UpdateTabVisuals();
        }

        #region 分类筛选

        /// <summary>
        /// 切换分类标签。
        /// </summary>
        public void SwitchTab(BuildingType type)
        {
            _currentTab = type;
            RefreshButtons();
            UpdateTabVisuals();
        }

        private void UpdateTabVisuals()
        {
            foreach (var kvp in _tabButtons)
            {
                if (kvp.Value == null) continue;
                var img = kvp.Value.GetComponent<Image>();
                if (img != null)
                {
                    img.color = kvp.Key == _currentTab ? _tabActiveColor : _tabInactiveColor;
                }
            }
        }

        #endregion

        #region 按钮生成

        /// <summary>
        /// 根据当前分类筛选并生成建筑按钮。
        /// </summary>
        public void RefreshButtons()
        {
            if (_buttonContainer == null || _buildingManager == null) return;

            // 清除旧按钮
            foreach (Transform child in _buttonContainer)
            {
                Destroy(child.gameObject);
            }

            var buildings = _buildingManager.AvailableBuildings;
            if (buildings == null) return;

            var profile = PlayerProfile.Instance;

            foreach (var data in buildings)
            {
                if (data == null) continue;
                // 按分类筛选
                if (data.buildingType != _currentTab) continue;

                GameObject buttonObj;
                if (_buildButtonPrefab != null)
                {
                    buttonObj = Instantiate(_buildButtonPrefab, _buttonContainer);
                }
                else
                {
                    buttonObj = CreateDefaultButton(data);
                }

                SetupButton(buttonObj, data, profile);
            }
        }

        private GameObject CreateDefaultButton(BuildingData data)
        {
            var go = new GameObject($"Btn_{data.buildingName}");
            go.transform.SetParent(_buttonContainer, false);

            var rect = go.AddComponent<RectTransform>();
            rect.sizeDelta = new Vector2(160f, 60f);

            var image = go.AddComponent<Image>();
            image.color = new Color(0.2f, 0.2f, 0.2f, 0.9f);

            var button = go.AddComponent<Button>();

            // 名称文本
            var textObj = new GameObject("Text");
            textObj.transform.SetParent(go.transform, false);
            var textRect = textObj.AddComponent<RectTransform>();
            textRect.anchorMin = Vector2.zero;
            textRect.anchorMax = Vector2.one;
            textRect.offsetMin = Vector2.zero;
            textRect.offsetMax = Vector2.zero;
            var text = textObj.AddComponent<Text>();
            text.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            text.fontSize = 14;
            text.alignment = TextAnchor.MiddleCenter;
            text.color = Color.white;
            var levelData = data.GetLevelData(1);
            text.text = $"{data.buildingName}\n{levelData.buildCost}G";

            return go;
        }

        private void SetupButton(GameObject buttonObj, BuildingData data, PlayerProfile profile)
        {
            var button = buttonObj.GetComponent<Button>();
            if (button == null) return;

            var levelData = data.GetLevelData(1);
            bool canAfford = profile != null && profile.HasEnoughGold(levelData.buildCost);

            // 负担不起时变灰
            if (!canAfford)
            {
                var colors = button.colors;
                colors.normalColor = new Color(0.5f, 0.5f, 0.5f, 1f);
                colors.highlightedColor = new Color(0.6f, 0.6f, 0.6f, 1f);
                button.colors = colors;
            }

            button.onClick.AddListener(() =>
            {
                if (_buildModeController != null)
                {
                    _buildModeController.EnterBuildMode(data);
                    Close();
                }
            });
        }

        #endregion

        #region 打开/关闭

        public void Open()
        {
            gameObject.SetActive(true);
            RefreshButtons();
            UpdateTabVisuals();
        }

        public void Close()
        {
            gameObject.SetActive(false);
        }

        #endregion
    }
}

using UnityEngine;
using UnityEngine.UI;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 建筑信息弹窗，显示已放置建筑的详情、升级和拆除功能。
    /// </summary>
    public class BuildingInfoPanel : MonoBehaviour
    {
        [Header("UI 引用")]
        [SerializeField] private Text _nameText;
        [SerializeField] private Text _levelText;
        [SerializeField] private Text _descText;
        [SerializeField] private Text _upgradeCostText;
        [SerializeField] private Button _upgradeButton;
        [SerializeField] private Button _demolishButton;
        [SerializeField] private Button _closeButton;

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;

        private BuildingBase _currentBuilding;

        public bool IsShowing => _currentBuilding != null;

        private void Awake()
        {
            if (_upgradeButton != null)
                _upgradeButton.onClick.AddListener(OnUpgradeClicked);
            if (_demolishButton != null)
                _demolishButton.onClick.AddListener(OnDemolishClicked);
            if (_closeButton != null)
                _closeButton.onClick.AddListener(Close);
        }

        private void OnDestroy()
        {
            if (_upgradeButton != null)
                _upgradeButton.onClick.RemoveListener(OnUpgradeClicked);
            if (_demolishButton != null)
                _demolishButton.onClick.RemoveListener(OnDemolishClicked);
            if (_closeButton != null)
                _closeButton.onClick.RemoveListener(Close);
        }

        /// <summary>
        /// 显示指定建筑的信息弹窗。
        /// </summary>
        public void Show(BuildingBase building)
        {
            if (building == null || building.Data == null) return;

            _currentBuilding = building;
            RefreshDisplay();
            gameObject.SetActive(true);
        }

        /// <summary>
        /// 关闭弹窗。
        /// </summary>
        public void Close()
        {
            _currentBuilding = null;
            gameObject.SetActive(false);
        }

        private void RefreshDisplay()
        {
            if (_currentBuilding == null) return;

            var data = _currentBuilding.Data;

            if (_nameText != null)
                _nameText.text = data.buildingName;

            if (_levelText != null)
                _levelText.text = $"Lv.{_currentBuilding.CurrentLevel}";

            if (_descText != null)
                _descText.text = data.description;

            // 升级按钮状态
            if (_upgradeButton != null)
            {
                bool canUpgrade = !_currentBuilding.IsMaxLevel;
                _upgradeButton.gameObject.SetActive(canUpgrade);

                if (canUpgrade)
                {
                    var nextLevel = data.GetLevelData(_currentBuilding.CurrentLevel + 1);
                    var profile = PlayerProfile.Instance;
                    bool canAfford = profile != null && profile.HasEnoughGold(nextLevel.upgradeCost);

                    if (_upgradeCostText != null)
                        _upgradeCostText.text = $"{nextLevel.upgradeCost}G";

                    _upgradeButton.interactable = canAfford;

                    var colors = _upgradeButton.colors;
                    colors.normalColor = canAfford ? Color.white : new Color(0.5f, 0.5f, 0.5f, 1f);
                    _upgradeButton.colors = colors;
                }
            }
        }

        private void OnUpgradeClicked()
        {
            if (_currentBuilding == null) return;

            if (_currentBuilding.Upgrade())
            {
                RefreshDisplay();
                Debug.Log($"[BuildingInfoPanel] 建筑升级成功: {_currentBuilding.Data.buildingName}");
            }
        }

        private void OnDemolishClicked()
        {
            if (_currentBuilding == null) return;

            int refund = _currentBuilding.GetSellValue();

            if (_buildingManager != null)
            {
                _buildingManager.RemoveBuilding(_currentBuilding);
            }
            else
            {
                _currentBuilding.Demolish();
            }

            _currentBuilding = null;
            gameObject.SetActive(false);

            Debug.Log($"[BuildingInfoPanel] 建筑已拆除，返还 {refund}G");
        }
    }
}

using UnityEngine;
using UnityEngine.UI;
using Sttop5.Shared.Core;
using Sttop5.Shared.Player;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主界面 UI，显示资源栏、建筑菜单和操作按钮。
    /// </summary>
    public class HomeMainUI : MonoBehaviour
    {
        [Header("资源栏")]
        [SerializeField] private Text _goldText;
        [SerializeField] private Text _diamondText;
        [SerializeField] private Text _woodText;
        [SerializeField] private Text _stoneText;
        [SerializeField] private Text _foodText;
        [SerializeField] private Text _levelText;

        [Header("按钮 - 顶部")]
        [SerializeField] private Button _settingsButton;
        [SerializeField] private Button _backpackButton;
        [SerializeField] private Button _shopButton;
        [SerializeField] private Button _friendButton;

        [Header("按钮 - 左侧")]
        [SerializeField] private Button _collectAllButton;
        [SerializeField] private Button _buildMenuButton;
        [SerializeField] private Button _taskButton;

        [Header("建筑菜单")]
        [SerializeField] private GameObject _buildMenuPanel;
        [SerializeField] private Transform _buildButtonContainer;
        [SerializeField] private BuildMenuUI _buildMenuUI;

        [Header("面板")]
        [SerializeField] private GameObject _settingsPanel;
        [SerializeField] private GameObject _taskPanel;

        [Header("设置面板按钮")]
        [SerializeField] private Button _resumeButton;
        [SerializeField] private Button _restartButton;
        [SerializeField] private Button _quitButton;

        [Header("建造模式提示")]
        [SerializeField] private GameObject _buildModeHint;
        [SerializeField] private BuildModeController _buildModeController;

        [Header("底部信息栏")]
        [SerializeField] private Text _bottomInfoText;

        [Header("组件引用")]
        [SerializeField] private HomeManager _homeManager;
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;

        private void Start()
        {
            SetupButtons();
            SubscribeEvents();
            RefreshUI();

            // 面板默认隐藏
            if (_buildModeHint != null)
                _buildModeHint.SetActive(false);
            if (_settingsPanel != null)
                _settingsPanel.SetActive(false);
            if (_taskPanel != null)
                _taskPanel.SetActive(false);

            // 监听建造模式状态变化
            if (_buildModeController != null)
                _buildModeController.OnStateChanged += OnBuildStateChanged;
        }

        private void OnDestroy()
        {
            UnsubscribeEvents();

            if (_buildModeController != null)
                _buildModeController.OnStateChanged -= OnBuildStateChanged;
        }

        private void SetupButtons()
        {
            // 左侧按钮
            if (_collectAllButton != null)
                _collectAllButton.onClick.AddListener(OnCollectAllClicked);

            if (_buildMenuButton != null)
                _buildMenuButton.onClick.AddListener(ToggleBuildMenu);

            if (_taskButton != null)
                _taskButton.onClick.AddListener(ToggleTaskPanel);

            // 顶部按钮
            if (_settingsButton != null)
                _settingsButton.onClick.AddListener(ToggleSettingsPanel);

            if (_backpackButton != null)
                _backpackButton.onClick.AddListener(() => ShowTips("背包功能即将开放"));

            if (_shopButton != null)
                _shopButton.onClick.AddListener(() => ShowTips("商店功能即将开放"));

            if (_friendButton != null)
                _friendButton.onClick.AddListener(() => ShowTips("好友功能即将开放"));

            // 设置面板按钮
            if (_resumeButton != null)
                _resumeButton.onClick.AddListener(CloseSettingsPanel);

            if (_restartButton != null)
                _restartButton.onClick.AddListener(OnRestartClicked);

            if (_quitButton != null)
                _quitButton.onClick.AddListener(OnQuitClicked);

            if (_buildMenuPanel != null)
                _buildMenuPanel.SetActive(false);
        }

        #region 事件订阅

        private void SubscribeEvents()
        {
            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                profile.OnGoldChanged += OnGoldChanged;
                profile.OnDiamondChanged += OnDiamondChanged;
                profile.OnLevelChanged += OnLevelChanged;
            }

            if (_resourceManager != null)
            {
                _resourceManager.OnLocalResourcesChanged += OnLocalResourcesChanged;
            }
        }

        private void UnsubscribeEvents()
        {
            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                profile.OnGoldChanged -= OnGoldChanged;
                profile.OnDiamondChanged -= OnDiamondChanged;
                profile.OnLevelChanged -= OnLevelChanged;
            }

            if (_resourceManager != null)
            {
                _resourceManager.OnLocalResourcesChanged -= OnLocalResourcesChanged;
            }
        }

        #endregion

        #region UI 更新

        private void RefreshUI()
        {
            var profile = PlayerProfile.Instance;
            if (profile != null)
            {
                SetText(_goldText, profile.Gold.ToString());
                SetText(_diamondText, profile.Diamond.ToString());
                SetText(_levelText, $"Lv.{profile.Level}");
            }

            if (_resourceManager != null)
            {
                SetText(_woodText, _resourceManager.Wood.ToString());
                SetText(_stoneText, _resourceManager.Stone.ToString());
                SetText(_foodText, _resourceManager.Food.ToString());
            }
        }

        private void OnGoldChanged(int gold)
        {
            SetText(_goldText, gold.ToString());
        }

        private void OnDiamondChanged(int diamond)
        {
            SetText(_diamondText, diamond.ToString());
        }

        private void OnLevelChanged(int level)
        {
            SetText(_levelText, $"Lv.{level}");
        }

        private void OnLocalResourcesChanged(int wood, int stone, int food)
        {
            SetText(_woodText, wood.ToString());
            SetText(_stoneText, stone.ToString());
            SetText(_foodText, food.ToString());
        }

        private void SetText(Text text, string value)
        {
            if (text != null) text.text = value;
        }

        #endregion

        #region 按钮回调

        private void OnCollectAllClicked()
        {
            _homeManager?.OnCollectAllClicked();
        }

        private void ToggleBuildMenu()
        {
            if (_buildMenuUI != null)
            {
                if (_buildMenuPanel != null)
                {
                    bool show = !_buildMenuPanel.activeSelf;
                    _buildMenuPanel.SetActive(show);
                    if (show) _buildMenuUI.Open();
                    else _buildMenuUI.Close();
                }
            }
            else if (_buildMenuPanel != null)
            {
                _buildMenuPanel.SetActive(!_buildMenuPanel.activeSelf);
            }
        }

        private void OnBuildStateChanged(BuildModeController.BuildState state)
        {
            if (_buildModeHint != null)
                _buildModeHint.SetActive(state == BuildModeController.BuildState.Placing);
        }

        #region 面板切换

        private void ToggleSettingsPanel()
        {
            if (_settingsPanel == null) return;
            bool show = !_settingsPanel.activeSelf;
            _settingsPanel.SetActive(show);
            if (show)
                Time.timeScale = 0f;
            else
                Time.timeScale = 1f;
        }

        private void CloseSettingsPanel()
        {
            if (_settingsPanel != null)
                _settingsPanel.SetActive(false);
            Time.timeScale = 1f;
        }

        private void ToggleTaskPanel()
        {
            if (_taskPanel == null) return;
            _taskPanel.SetActive(!_taskPanel.activeSelf);
        }

        private void OnRestartClicked()
        {
            Time.timeScale = 1f;
            UnityEngine.SceneManagement.SceneManager.LoadScene(
                UnityEngine.SceneManagement.SceneManager.GetActiveScene().name);
        }

        private void OnQuitClicked()
        {
#if UNITY_EDITOR
            UnityEditor.EditorApplication.isPlaying = false;
#else
            Application.Quit();
#endif
        }

        private void ShowTips(string msg)
        {
            Debug.Log($"[HomeMainUI] {msg}");
            if (_bottomInfoText != null)
            {
                _bottomInfoText.text = msg;
                CancelInvoke(nameof(ClearTips));
                Invoke(nameof(ClearTips), 2f);
            }
        }

        private void ClearTips()
        {
            if (_bottomInfoText != null)
                _bottomInfoText.text = "";
        }

        #endregion

        /// <summary>
        /// 返回按钮回调（返回家园或退出）。
        /// </summary>
        public void OnBackClicked()
        {
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null && moduleManager.ActiveModuleId != "home")
            {
                moduleManager.DeactivateCurrentModule();
            }
        }

        #endregion
    }
}

using System;
using UnityEngine;
using Sttop5.Shared.Core;
using Sttop5.Shared.Save;

namespace Sttop5.Modules.HomeBase
{
    /// <summary>
    /// 家园主控制器，管理家园场景的初始化和生命周期。
    /// 作为 GameModule 注册到 ModuleManager。
    /// </summary>
    public class HomeManager : GameModule
    {
        private const string MODULE_ID = "home";
        private const string MODULE_DISPLAY_NAME = "家园";
        private const string SAVE_KEY = "homebase";

        [Header("组件引用")]
        [SerializeField] private BuildingManager _buildingManager;
        [SerializeField] private ResourceManager _resourceManager;
        [SerializeField] private BuildingInfoPanel _buildingInfoPanel;

        [Header("初始建筑")]
        [SerializeField] private BuildingData[] _starterBuildings;
        [SerializeField] private Vector3[] _starterPositions;

        private bool _isLoaded = false;

        private void Awake()
        {
            _moduleId = MODULE_ID;
            _displayName = MODULE_DISPLAY_NAME;
            _sceneName = gameObject.scene.name;
        }

        private void Start()
        {
            InitializeHome();
        }

        private void InitializeHome()
        {
            if (_isLoaded) return;

            // 注册到 ModuleManager
            var moduleManager = ModuleManager.Instance;
            if (moduleManager != null)
            {
                moduleManager.RegisterModule(this);
            }

            // 尝试从存档加载
            LoadHomeSave();

            // 如果没有建筑，放置初始建筑
            if (_buildingManager.Buildings.Count == 0)
            {
                PlaceStarterBuildings();
            }

            // 注册建筑点击事件
            foreach (var building in _buildingManager.Buildings)
            {
                if (building != null)
                    building.OnBuildingClicked += OnBuildingClicked;
            }

            // 新放置的建筑也自动注册
            _buildingManager.OnBuildingPlaced += (b) =>
            {
                if (b != null) b.OnBuildingClicked += OnBuildingClicked;
            };

            _isLoaded = true;
            Debug.Log("[HomeManager] 家园初始化完成");
        }

        private void PlaceStarterBuildings()
        {
            if (_starterBuildings == null || _starterPositions == null) return;

            int count = Mathf.Min(_starterBuildings.Length, _starterPositions.Length);
            for (int i = 0; i < count; i++)
            {
                if (_starterBuildings[i] != null)
                {
                    _buildingManager.PlaceBuilding(_starterBuildings[i], _starterPositions[i]);
                }
            }

            Debug.Log($"[HomeManager] 放置 {count} 个初始建筑");
        }

        #region 存档

        public override string GetModuleSaveData()
        {
            var saveData = new HomeSaveData();
            _resourceManager?.SaveToSave(saveData);
            saveData.buildings = _buildingManager?.ExportSaveData();
            return JsonUtility.ToJson(saveData);
        }

        public override void RestoreModuleSaveData(string jsonData)
        {
            if (string.IsNullOrEmpty(jsonData)) return;

            try
            {
                var saveData = JsonUtility.FromJson<HomeSaveData>(jsonData);
                _resourceManager?.LoadFromSave(saveData);
                _buildingManager?.RestoreFromSaveData(saveData.buildings);
            }
            catch (Exception e)
            {
                Debug.LogError($"[HomeManager] 恢复存档失败: {e.Message}");
            }
        }

        private void LoadHomeSave()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = saveSystem.LoadModuleData(SAVE_KEY);
            if (!string.IsNullOrEmpty(json))
            {
                RestoreModuleSaveData(json);
                Debug.Log("[HomeManager] 家园存档已加载");
            }
        }

        private void SaveHomeData()
        {
            var saveSystem = SaveSystem.Instance;
            if (saveSystem == null) return;

            string json = GetModuleSaveData();
            saveSystem.SaveModuleData(SAVE_KEY, json, 1);
        }

        #endregion

        #region 模块生命周期

        public override void Activate()
        {
            base.Activate();
            Debug.Log("[HomeManager] 家园已激活");
        }

        public override void Deactivate()
        {
            SaveHomeData();
            base.Deactivate();
            Debug.Log("[HomeManager] 家园已停用");
        }

        #endregion

        #region 按钮回调

        /// <summary>
        /// 收集所有资源按钮回调。
        /// </summary>
        public void OnCollectAllClicked()
        {
            _resourceManager?.CollectAllResources();
        }

        /// <summary>
        /// 建筑被点击时的回调，打开建筑信息弹窗。
        /// </summary>
        private void OnBuildingClicked(BuildingBase building)
        {
            if (_buildingInfoPanel != null)
                _buildingInfoPanel.Show(building);
        }

        #endregion

        private void OnApplicationPause(bool pauseStatus)
        {
            if (pauseStatus) SaveHomeData();
        }

        private void OnApplicationQuit()
        {
            SaveHomeData();
        }
    }
}

