using UnityEngine;
using Sttop5.Modules.HomeBase;

// === 1. 在 BuildingManager 上：删除 GridManager 组件，添加 PlacementManager ===
var bm = UnityEngine.Object.FindObjectOfType<BuildingManager>();
if (bm != null)
{
    var go = bm.gameObject;

    // 删除旧的 GridManager
    var oldGrid = go.GetComponent<GridManager>();
    if (oldGrid != null)
    {
        Debug.Log("[Wiring] Removing GridManager component");
        UnityEngine.Object.DestroyImmediate(oldGrid);
    }

    // 添加 PlacementManager（如果不存在）
    var pm = go.GetComponent<PlacementManager>();
    if (pm == null)
    {
        pm = go.AddComponent<PlacementManager>();
        Debug.Log("[Wiring] Added PlacementManager component");
    }

    // 绑定 BuildingManager._placementManager
    var so = new UnityEditor.SerializedObject(bm);
    so.FindProperty("_placementManager").objectReferenceValue = pm;
    so.ApplyModifiedProperties();
    Debug.Log("[Wiring] BuildingManager._placementManager linked");

    // 绑定 BuildModeController._placementManager
    var bmc = go.GetComponent<BuildModeController>();
    if (bmc != null)
    {
        var so2 = new UnityEditor.SerializedObject(bmc);
        so2.FindProperty("_placementManager").objectReferenceValue = pm;
        so2.ApplyModifiedProperties();
        Debug.Log("[Wiring] BuildModeController._placementManager linked");
    }

    // 设置 PlacementManager._groundLayer = Ground (bit 8)
    int groundLayerIndex = LayerMask.NameToLayer("Ground");
    var so3 = new UnityEditor.SerializedObject(pm);
    so3.FindProperty("_groundLayer").intValue = 1 << groundLayerIndex;
    so3.ApplyModifiedProperties();
    Debug.Log("[Wiring] PlacementManager._groundLayer = Ground");
}

